function Invoke-PortScan {
    param(
        [string]$Target,
        [string]$Ports,
        [int]$Timeout = 1000
    )
    $portList = $Ports -split '[,\s]+' | Where-Object { $_ -match '^\d+$' }
    $results = @()
    foreach ($port in $portList) {
        $tcp = New-Object System.Net.Sockets.TcpClient
        try {
            $async = $tcp.BeginConnect($Target, [int]$port, $null, $null)
            $wait = $async.AsyncWaitHandle.WaitOne($Timeout, $false)
            if ($wait -and $tcp.Connected) {
                $results += @{ port = [int]$port; status = 'open' }
            } else {
                $results += @{ port = [int]$port; status = 'closed' }
            }
        } catch {
            $results += @{ port = [int]$port; status = 'error'; error = $_.Exception.Message }
        } finally {
            $tcp.Close()
        }
    }
    return @{ target = $Target; scanned = $results.Count; ports = $results } | ConvertTo-Json -Depth 3
}

Invoke-PortScan -Target '{{target}}' -Ports '{{ports}}' -Timeout {{timeout}}
